export function identifier_(text: string) {
  if (RESERVED_KEYWORDS.has(text)) throw new Error(`'${text}' is a reserved keyword, not a valid identifier`);
  if (!/^[_\p{XID_Start}][_\p{XID_Continue}]*$/u.test(text)) throw new Error(`Invalid identifier: '${text}' does not match grammar pattern`);
  return {
    type: 'identifier' as const,
    named: true as const,
    text,
    render: () => text,
    toEdit: (startOrRange: number | { start: { index: number }; end: { index: number } }, endPos?: number) => {
      if (typeof startOrRange === 'number') {
        if (endPos === undefined) throw new Error('endPos required when startPos is a number');
        return { startPos: startOrRange, endPos, insertedText: text };
      }
      return { startPos: startOrRange.start.index, endPos: startOrRange.end.index, insertedText: text };
    },
    replace: (target: IdentifierTree) => { const r = target.range(); return { startPos: r.start.index, endPos: r.end.index, insertedText: text }; },
  };
}

